def specialFilter(nums):
    def is_odd_first_last_digit(n):
        n = abs(n)
        if n < 10:
            return n % 2 != 0
        last_digit = n % 10
        while n >= 10:
            n //= 10
        first_digit = n
        return first_digit % 2 != 0 and last_digit % 2 != 0

    return sum(1 for num in nums if num > 10 and is_odd_first_last_digit(num))
